 1	import React, { FC } from 'react';
 2	
 3	import { V1beta1DataImportCron } from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 4	import {
 5	  ConditionsTable,
 6	  K8sResourceCondition,
 7	} from '@kubevirt-utils/components/ConditionsTable/ConditionsTable';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { Divider, PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
10	
11	import { DataImportCronDetailsGrid } from './DataImportCronDetailsGrid';
12	
13	type DataImportCronDetailsPageProps = {
14	  obj?: V1beta1DataImportCron;
15	};
16	
17	const DataImportCronDetailsPage: FC<DataImportCronDetailsPageProps> = ({ obj: dataImportCron }) => {
18	  const { t } = useKubevirtTranslation();
19	
20	  return (
21	    <div>
22	      <PageSection variant={PageSectionVariants.light}>
23	        <Title className="co-section-heading" headingLevel="h2">
24	          {t('DataImportCron details')}
25	        </Title>
26	        <DataImportCronDetailsGrid dataImportCron={dataImportCron} />
27	      </PageSection>
28	      <Divider />
29	      <PageSection variant={PageSectionVariants.light}>
30	        <Title className="co-section-heading" headingLevel="h2">
31	          {t('Conditions')}
32	        </Title>
33	        <ConditionsTable
34	          conditions={dataImportCron?.status?.conditions as K8sResourceCondition[]}
35	        />
36	      </PageSection>
37	    </div>
38	  );
39	};
40	
41	export default DataImportCronDetailsPage;

